/**
 * Regression tests for the explicit-review routing path in the model-router extension.
 *
 * Covers:
 *   1. isSameModelFamily – codex GPT variants must be treated as the same family as non-codex GPT
 *   2. orderCandidates   – cross-family candidates must rank before same-family candidates for review
 *   3. reviewDiversityFallback – the computed outcome must be null / "same-family" / "exact-reuse"
 *
 * Uses Node's built-in test runner (node:test). No external dependencies.
 * Run with:  node --test tests/review-diversity.test.mjs
 */

import { test } from "node:test";
import assert from "node:assert/strict";

// ── Inline copies of the pure helpers (keep in sync with extension.mjs) ──────

const MODEL_FAMILIES = {
  claude: new Set([
    "claude-haiku-4.5",
    "claude-sonnet-4",
    "claude-sonnet-4.5",
    "claude-sonnet-4.6",
    "claude-opus-4.5",
    "claude-opus-4.6",
    "claude-opus-4.6-1m",
  ]),
  gpt: new Set([
    "gpt-4.1",
    "gpt-5-mini",
    "gpt-5.4-mini",
    "gpt-5.1",
    "gpt-5.2",
    "gpt-5.3-codex",
    "gpt-5.1-codex",
    "gpt-5",
    "gpt-5.4",
    "gpt-5.1-codex-max",
  ]),
};

function getModelFamily(modelId) {
  if (!modelId) return null;
  if (MODEL_FAMILIES.claude.has(modelId)) return "claude";
  if (MODEL_FAMILIES.gpt.has(modelId)) return "gpt";
  return null;
}

// Fixed version – delegates to getModelFamily so all GPT (including codex) = "gpt",
// all Claude = "claude".
function isSameModelFamily(first, second) {
  if (!first || !second) return false;
  return getModelFamily(first) === getModelFamily(second);
}

// Reproduces the old inline logic that was removed – kept here only to document
// and assert the old (wrong) behaviour for the regression test.
function isSameModelFamily_old(first, second) {
  if (!first || !second) return false;
  const family = (model) => {
    if (model.startsWith("claude-haiku")) return "claude-haiku";
    if (model.startsWith("claude-sonnet")) return "claude-sonnet";
    if (model.startsWith("claude-opus")) return "claude-opus";
    if (model.includes("codex")) return "codex";    // ← the bug
    if (model.startsWith("gpt-5")) return "gpt-5";
    if (model.startsWith("gpt-4.1")) return "gpt-4.1";
    return model;
  };
  return family(first) === family(second);
}

function orderCandidates(candidates, lastImplementationModel) {
  if (!lastImplementationModel) return candidates;
  return [...candidates].sort((left, right) => {
    const score = (id) =>
      id === lastImplementationModel ? 2 : isSameModelFamily(id, lastImplementationModel) ? 1 : 0;
    return score(left.id) - score(right.id);
  });
}

function computeReviewDiversityFallback(reviewedWith, lastImplementationModel) {
  if (!lastImplementationModel) return null;
  if (reviewedWith === lastImplementationModel) return "exact-reuse";
  if (isSameModelFamily(reviewedWith, lastImplementationModel)) return "same-family";
  return null;
}

// ── Bug 1 regression: codex GPT variants belong to the same family as non-codex GPT ──

test("REGRESSION isSameModelFamily: codex GPT must be same family as non-codex GPT", () => {
  // Old code treated codex models as a separate "codex" sub-family; new code correctly
  // uses MODEL_FAMILIES which puts all gpt-* models in the "gpt" family.
  assert.equal(isSameModelFamily_old("gpt-5.3-codex", "gpt-5.2"), false,
    "old code: codex wrongly treated as different family");
  assert.equal(isSameModelFamily("gpt-5.3-codex", "gpt-5.2"), true,
    "new code: codex is same gpt family");

  assert.equal(isSameModelFamily_old("gpt-5.1-codex", "gpt-5.1"), false,
    "old code: gpt-5.1-codex wrongly different from gpt-5.1");
  assert.equal(isSameModelFamily("gpt-5.1-codex", "gpt-5.1"), true,
    "new code: gpt-5.1-codex is same gpt family as gpt-5.1");

  assert.equal(isSameModelFamily_old("gpt-5.1-codex-max", "gpt-5.4"), false,
    "old code: gpt-5.1-codex-max wrongly different from gpt-5.4");
  assert.equal(isSameModelFamily("gpt-5.1-codex-max", "gpt-5.4"), true,
    "new code: gpt-5.1-codex-max is same gpt family as gpt-5.4");
});

// ── isSameModelFamily correctness ─────────────────────────────────────────────

test("isSameModelFamily: all claude sub-types are the same family", () => {
  assert.equal(isSameModelFamily("claude-haiku-4.5", "claude-sonnet-4.6"), true);
  assert.equal(isSameModelFamily("claude-opus-4.6", "claude-sonnet-4.5"), true);
  assert.equal(isSameModelFamily("claude-haiku-4.5", "claude-opus-4.5"), true);
});

test("isSameModelFamily: all gpt variants (including codex) are the same family", () => {
  assert.equal(isSameModelFamily("gpt-5.3-codex", "gpt-5.2"), true);
  assert.equal(isSameModelFamily("gpt-5.1-codex", "gpt-5.4"), true);
  assert.equal(isSameModelFamily("gpt-4.1", "gpt-5-mini"), true);
  assert.equal(isSameModelFamily("gpt-5.1-codex-max", "gpt-5"), true);
});

test("isSameModelFamily: cross-family returns false", () => {
  assert.equal(isSameModelFamily("gpt-5", "claude-sonnet-4.6"), false);
  assert.equal(isSameModelFamily("gpt-5.3-codex", "claude-opus-4.6"), false);
  assert.equal(isSameModelFamily("claude-haiku-4.5", "gpt-5-mini"), false);
});

test("isSameModelFamily: null/undefined inputs return false", () => {
  assert.equal(isSameModelFamily(null, "gpt-5"), false);
  assert.equal(isSameModelFamily("claude-sonnet-4.6", null), false);
  assert.equal(isSameModelFamily(null, null), false);
  assert.equal(isSameModelFamily(undefined, "gpt-5"), false);
});

// ── Bug 1 impact on orderCandidates for review diversity ──────────────────────

test("orderCandidates: when impl was GPT, codex GPT ranked same as other GPT (behind claude)", () => {
  const candidates = [
    { id: "gpt-5" },
    { id: "claude-sonnet-4.6" },
    { id: "gpt-5.3-codex" },
    { id: "claude-opus-4.6" },
  ];
  const ordered = orderCandidates(candidates, "gpt-5.2");
  const ids = ordered.map((c) => c.id);

  // claude models must all come before gpt models in the sorted output
  const firstGptIndex = Math.min(
    ids.indexOf("gpt-5"),
    ids.indexOf("gpt-5.3-codex"),
  );
  const lastClaudeIndex = Math.max(
    ids.indexOf("claude-sonnet-4.6"),
    ids.indexOf("claude-opus-4.6"),
  );
  assert.ok(
    lastClaudeIndex < firstGptIndex,
    `Expected all claude models before all gpt models. Got: ${ids.join(", ")}`,
  );
});

test("orderCandidates: when impl was claude-sonnet, cross-family GPT candidates come first", () => {
  const candidates = [
    { id: "gpt-5" },
    { id: "gpt-5.4" },
    { id: "claude-sonnet-4.6" },
    { id: "claude-opus-4.5" },
  ];
  const ordered = orderCandidates(candidates, "claude-sonnet-4.5");
  const ids = ordered.map((c) => c.id);

  // gpt-5 and gpt-5.4 are cross-family (score 0) so they come before claude (score 0 or 1)
  // claude-sonnet-4.6 is same subfamily in old code (score 1) but cross-family claude in
  // family-level comparison; either way gpt must be before it.
  assert.ok(ids.indexOf("gpt-5") < ids.indexOf("claude-sonnet-4.6"),
    `gpt-5 should rank before claude-sonnet-4.6 when impl was claude-sonnet-4.5`);
  assert.ok(ids.indexOf("gpt-5.4") < ids.indexOf("claude-sonnet-4.6"),
    `gpt-5.4 should rank before claude-sonnet-4.6`);
});

test("orderCandidates: exact impl model is ranked last", () => {
  const candidates = [
    { id: "gpt-5" },
    { id: "claude-sonnet-4.6" },
    { id: "claude-sonnet-4.5" }, // same as impl model
  ];
  const ordered = orderCandidates(candidates, "claude-sonnet-4.5");
  assert.equal(ordered[ordered.length - 1].id, "claude-sonnet-4.5",
    "The implementation model should be ranked last");
});

// ── Bug 2 regression: reviewDiversityFallback values ─────────────────────────

test("reviewDiversityFallback: null when cross-family diversity achieved", () => {
  assert.equal(computeReviewDiversityFallback("gpt-5", "claude-sonnet-4.5"), null);
  assert.equal(computeReviewDiversityFallback("claude-opus-4.6", "gpt-5.2"), null);
});

test("reviewDiversityFallback: same-family when family matches but model differs", () => {
  assert.equal(
    computeReviewDiversityFallback("claude-sonnet-4.6", "claude-sonnet-4.5"),
    "same-family",
  );
  assert.equal(
    computeReviewDiversityFallback("gpt-5.3-codex", "gpt-5.2"),
    "same-family",
    "codex GPT review after non-codex GPT impl must be same-family fallback",
  );
  assert.equal(
    computeReviewDiversityFallback("gpt-5", "gpt-5.4"),
    "same-family",
  );
});

test("reviewDiversityFallback: exact-reuse when review model is identical to impl model", () => {
  assert.equal(
    computeReviewDiversityFallback("claude-sonnet-4.6", "claude-sonnet-4.6"),
    "exact-reuse",
  );
  assert.equal(
    computeReviewDiversityFallback("gpt-5", "gpt-5"),
    "exact-reuse",
  );
});

test("reviewDiversityFallback: null when no prior implementation model", () => {
  assert.equal(computeReviewDiversityFallback("gpt-5", null), null);
  assert.equal(computeReviewDiversityFallback("gpt-5", undefined), null);
});

